% Generated by textlayout from the official openEMS finite CPW pattern.
close all; clear; clc;
addpath('.tools/openems-wsl/share/openEMS/matlab');
addpath('.tools/openems-wsl/share/CSXCAD/matlab');
setenv('PATH', ['.tools/openems-wsl/bin' pathsep getenv('PATH')]);
setenv('LD_LIBRARY_PATH', ['.tools/openems-wsl/lib' pathsep '.tools/openems-wsl/lib64' pathsep getenv('LD_LIBRARY_PATH')]);
physical_constants; unit = 1e-6;
f_start = 3000000000; f_stop = 9000000000;
FDTD = InitFDTD('NrTS', 180000, 'EndCriteria', 1e-3);
FDTD = SetGaussExcite(FDTD, (f_start+f_stop)/2, (f_stop-f_start)/2);
FDTD = SetBoundaryCond(FDTD, [2 2 2 2 2 2]);
CSX = InitCSX();
mesh.x = SmoothMeshLines([-621.966 -500 0 500 621.966], 40, 1.4, 0);
mesh.y = SmoothMeshLines([-10.983 -5 5 10.983], 1.99433333, 1.3, 0);
mesh.y = SmoothMeshLines([-182.949 -60.983 mesh.y 60.983 182.949], 40, 1.4, 0);
mesh.z = SmoothMeshLines([-121.966 0 500 621.966], 40, 1.4, 0);
CSX = DefineRectGrid(CSX, unit, mesh);
CSX = AddMaterial(CSX, 'substrate', 'Epsilon', 11.9);
CSX = AddBox(CSX, 'substrate', 0, [-500 -60.983 0], [500 60.983 500]);
CSX = AddMetal(CSX, 'CPW_PORT');
[CSX, port{1}] = AddCPWPort(CSX, 999, 1, 'CPW_PORT', [-500 -5 500], [-300 5 500], 5.983, 'x', [0 1 0], 'ExcitePort', true, 'MeasPlaneShift', 200, 'Feed_R', 50);
[CSX, port{2}] = AddCPWPort(CSX, 999, 2, 'CPW_PORT', [500 -5 500], [300 5 500], 5.983, 'x', [0 1 0], 'MeasPlaneShift', 200, 'Feed_R', 50);
CSX = AddMetal(CSX, 'CPW');
CSX = AddBox(CSX, 'CPW', 999, [-300 -5 500], [300 5 500]);
CSX = AddMetal(CSX, 'GND');
CSX = AddBox(CSX, 'GND', 999, [-500 -60.983 500], [500 -10.983 500]);
CSX = AddBox(CSX, 'GND', 999, [-500 10.983 500], [500 60.983 500]);
Sim_Path = 'openems_run'; Sim_CSX = 'model.xml';
CleanupSimPath(Sim_Path);
WriteOpenEMS(fullfile(Sim_Path, Sim_CSX), FDTD, CSX);
RunOpenEMS(Sim_Path, Sim_CSX);
freq = linspace(f_start, f_stop, 401);
port = calcPort(port, Sim_Path, freq, 'RefImpedance', 50);
s11 = port{1}.uf.ref ./ port{1}.uf.inc;
s21 = port{2}.uf.ref ./ port{1}.uf.inc;
fid = fopen('openems_result.s2p', 'w'); fprintf(fid, '# Hz S RI R 50\n');
for k=1:numel(freq)
  fprintf(fid, '%.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e %.12e\n', freq(k), real(s11(k)), imag(s11(k)), real(s21(k)), imag(s21(k)), real(s21(k)), imag(s21(k)), real(s11(k)), imag(s11(k)));
end; fclose(fid);
fid = fopen('openems_metrics.csv', 'w');
fprintf(fid, 'frequency_hz,z0_real,z0_imag,s11_real,s11_imag,s21_real,s21_imag\n');
for k=1:numel(freq)
  fprintf(fid, '%.12e,%.12e,%.12e,%.12e,%.12e,%.12e,%.12e\n', freq(k), real(port{1}.ZL(k)), imag(port{1}.ZL(k)), real(s11(k)), imag(s11(k)), real(s21(k)), imag(s21(k)));
end; fclose(fid);
